import 'dart:io';
import 'package:http/http.dart' as http;

Future<String> getData(String url) async {
  try{
    var response = await http.get(url);

    if (response == null ||
        response.statusCode != 200){
      return "Error: ${response?.statusCode}";
    }

    return response.body;

  } catch (error) {
    return 'Error: ${error}';
  }
}